# OEIS sequence: A133297

from math import factorial
def a(n: int) -> int:
    if n == 0: return 0
    t = factorial(n - 1)
    if n % 2 == 0: t = -t
    f = t
    for k in range(n, 1, -1):
        t = -n * t // (n - k + 1)
        f += t
    return f
print([a(n) for n in range(0, 21)])  # _Peter Luschny_, Mar 09 2026

